head.script:
//-------------------------------------------------------------------------
// 추후 작업 예정
// 1. 호출 팝업 미개발 op_202_02_27p
//-------------------------------------------------------------------------


//-------------------------------------------------------------------------
// 전역변수
//-------------------------------------------------------------------------
// 화면내 hidden 컴포넌트
scwin.hid_userId = "";
scwin.hid_odrNo = "";
scwin.hid_wrkStpCd = "";
scwin.hid_odrWrkStpSeq = "";
scwin.hid_lobranCd = "";


scwin.nowDt = WebSquare.date.getCurrentServerDate();  // 서버를 기준으로 현재 날짜 반환
scwin.nextDt = WebSquare.date.dateAdd(scwin.nowDt, 1);
scwin.loUpperLobranCd = $c.data.getMemInfo("loUpperLobranCd"); // 회원 점소 데이터

// 호출화면에서부터 전달받는 파라미터 
scwin.param = "";
scwin.lobranCd = "";
scwin.wrkStDt = "";
scwin.wrkEndDt = "";

scwin.afterSaveRetrieveYN = "YES";
scwin.afterCancelRetrieveYN = "YES";
scwin.olddata = "";

//-------------------------------------------------------------------------
// 화면 로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function () {

    scwin.param = $c.data.getParameter();
    scwin.wrkStDt = scwin.param.wrkStDt == null ? "" : scwin.param.wrkStDt;
    scwin.wrkEndDt = scwin.param.wrkEndDt == null ? "" : scwin.param.wrkEndDt;
    scwin.lobranCd = scwin.param.lobranCd == null ? "" : scwin.param.lobranCd;

    const param = [
        {
            method: "getLuxeComboData",
            param1: "WorkImplementEBC",
            param2: "retriveLobran2CodeList",
            param3: ["1"],
            compID: "acb_lobranCd"

        }
    ];
    $c.data.setGauceUtil(param);


    acb_qryClsCd.setValue("A"); /*A:FIX,B:NON FIX*/
    acb_odrClsCd.setValue("D"); /*A:FIX,B:NON FIX*/



    cbx_retrvStpYn.setValue("1");
    cbx_reqYn.setValue("1");
};


//-------------------------------------------------------------------------
// 공통 코드 로딩 되면서 UDC도 같이
//-------------------------------------------------------------------------
setTimeout (scwin.ondataload = function () {
    if (scwin.wrkStDt == "") {
        udc_dptIntendDd.setInitDate(scwin.nowDt, scwin.nowDt);
    } else {
        udc_dptIntendDd.setInitDate(scwin.wrkStDt, scwin.wrkEndDt);
    }

    if (scwin.lobranCd == "") {
        acb_lobranCd.setValue(scwin.loUpperLobranCd);
    } else {
        acb_lobranCd.setValue(scwin.lobranCd);
    }

},350);

scwin.onUdcComplete = function () {

    // if (scwin.wrkStDt == "") {
    //     udc_dptIntendDd.setInitDate(scwin.nowDt, scwin.nowDt);
    // } else {
    //     udc_dptIntendDd.setInitDate(scwin.wrkStDt, scwin.wrkEndDt);
    // }

    // if (scwin.lobranCd == "") {
    //     acb_lobranCd.setValue(scwin.loUpperLobranCd);
    // } else {
    //     acb_lobranCd.setValue(scwin.lobranCd);
    // }

};


//-------------------------------------------------------------------------
// 대문자 변환
//-------------------------------------------------------------------------
scwin.onkeyup = function (e) {
    this.setValue(e.target.value.toUpperCase());
};


//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.btn_retrieve_onclick = async function (e) {

    if (! await $c.gus.cfIsAfterDate(ica_dptIntendDd.getValue(), ica_dptIntendDd2.getValue())) {
        $c.win.alert(MSG_CM_ERR_039);
        ica_dptIntendDd.focus();
        return;
    }


    dma_search.set("lobranCd", acb_lobranCd.getValue());
    dma_search.set("dptIntendDd", ica_dptIntendDd.getValue());
    dma_search.set("dptIntendDd2", ica_dptIntendDd2.getValue());
    // dma_search.set("cntrWrkKndCd", acb_cntrWrkKndCd.getValue());
    dma_search.set("bilgClntNo", ed_bilgClntNo.getValue());
    dma_search.set("userId", scwin.hid_userId);
    dma_search.set("qryClsCd", acb_qryClsCd.getValue());
    dma_search.set("impExpClsCd", acb_impExpClsCd.getValue());
    dma_search.set("odrClsCd", acb_odrClsCd.getValue());
    dma_search.set("lineCd", ed_lineCd.getValue());
    dma_search.set("fromDt", ica_fromDt.getValue());
    dma_search.set("toDt", ica_toDt.getValue());
    dma_search.set("odrNo", ed_odrNo.getValue());
    dma_search.set("cntrNo", ed_cntrNo.getValue());
    dma_search.set("mgntNo", ed_mgntNo.getValue());


    $c.sbm.execute(sbm_retrieve);

};


//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.btn_save_onclick = async function (e) {


    let preChecked = cbx_retrvStpYn.getValue();
    if (cbx_retrvStpYn.getValue() == "1") {
        cbx_retrvStpYn.setValue("");
        scwin.f_filter();
    }



    if (ds_results.getModifiedIndex().length == 0) {
        $c.win.alert("변경된 사항이 없습니다.");
        return;
    }

    let arryCnt = 0;
    let arryCnt2 = 0;


    for (i = 0; i < ds_results2.getRowCount(); i++) {
        if (ds_results2.getCellData(i, "chk") == "1") {
            arryCnt2++;
        }

        if (ds_results2.getCellData(i, "chk") == "1" && ds_results2.getCellData(i, "allocYn") == "N") {
            $c.win.alert("이미요청되었습니다.");
            return;
        }

    }






    for (i = 0; i < ds_results.getRowCount(); i++) {
        if (ds_results.getModifiedIndex().length > 0 && ds_results.getRowStatus(i) == "U" && (ds_results.getCellData(i, "reqClsCd") == "A" || ds_results.getCellData(i, "reqClsCd") == "B")) {
            if (ds_results.getCellData(i, "reqQty") == "0" || ds_results.getCellData(i, "reqQty") == "") {
                $c.win.alert("요청수량은 1보다 커야합니다.");
                return;
            }
            if (ds_results.getCellData(i, "pastReqCnt") == ds_results.getCellData(i, "qty")) {
                $c.win.alert("더이상 요청할 수 없습니다.");
                return;
            }
            if (ds_results.getCellData(i, "remains") < ds_results.getCellData(i, "reqQty")) {
                $c.win.alert("잔량보다 많은 수를 요청할 수 없습니다.");
                return;
            }

            if (ds_results.getCellData(i, "reqDt") == "" || ds_results.getCellData(i, "reqHh") == "") {
                $c.win.alert("요청일자 및 일시는 필수 입니다.");
                return;
            }
            if (ds_results.getCellData(i, "reqClsCd") == "A" && (ds_results.getCellData(i, "arvWrkPlCd") == "43D" || ds_results.getCellData(i, "dptWrkPlCd") == "43D")) {
                $c.win.alert("대표착지는 요청할수 없습니다.");
                return;
            }

            if (
                ds_results.getCellData(i, "reqClsCd") == "B" &&
                (ds_results.getCellData(i, "arvWrkPlCd") == "43D" || ds_results.getCellData(i, "dptWrkPlCd") == "43D")
                && ds_results.getCellData(i, "doorCd") == ""
            ) {
                $c.win.alert("미지정 대표착지의 경우  Door를 입력하십시요.");
                return;
            }

            arryCnt++;
        } else if (ds_results.getModifiedIndex().length > 0 && ds_results.getRowStatus(i) == "U" && ds_results.getCellData(i, "reqClsCd") == "C") {

            if (ds_results.getCellData(i, "reqQty") == "0" || ds_results.getCellData(i, "reqQty") == "") {
                $c.win.alert("요청수량은 1보다 커야합니다.");
                return;
            }
            if (ds_results.getCellData(i, "pastReqCnt") == ds_results.getCellData(i, "qty")) {
                $c.win.alert("더이상 요청할 수 없습니다.");
                return;
            }
            if (ds_results.getCellData(i, "remains") < ds_results.getCellData(i, "reqQty")) {
                $c.win.alert("잔량보다 많은 수를 요청할 수 없습니다.");
                return;
            }

            if (ds_results.getCellData(i, "reqDt") == "" || ds_results.getCellData(i, "reqHh") == "") {
                $c.win.alert("요청일자 및 일시는 필수 입니다.");
                return;
            }

            if (arryCnt2 == "0") {
                $c.win.alert("선택된 컨테이너가 없습니다.");
                return;
            }

            if (ds_results.getCellData(i, "reqQty") != arryCnt2) {
                $c.win.alert("요청수량과 컨테이너의 수가 같지 않습니다.");
                return;
            }


            if ((ds_results.getCellData(i, "arvWrkPlCd") == "43D" || ds_results.getCellData(i, "dptWrkPlCd") == "43D") && ds_results.getCellData(i, "doorCd") == "") {

                for (i = 0; i < ds_results2.getRowCount(); i++) {

                    if (ds_results2.getCellData(i, "chk") == "1" && ds_results2.getCellData(i, "doorCd") == "") {
                        $c.win.alert("지정 범위 대표착지의 경우 Door는 필수입니다.");
                        return;
                    }


                }
            }



        }
    }






    for (i = 0; i < ds_results.getRowCount(); i++) {
        if (ds_results.getCellData(i, "wrkStpCd") == "0002"
            && ds_results.getRowStatus(i) == "U"
            && ds_results.getCellData(i, "transCls") != "B"
            && ds_results.getCellData(i, "transCls") != "O"
            && ds_results.getCellData(i, "transCls") != "IO") {
            if (ds_results.getCellData(i + 1, "wrkStpCd") == "0003"
                && ds_results.getCellData(i, "odrNo") == ds_results.getCellData(i + 1, "odrNo")
                && ds_results.getCellData(i + 1, "reqDt") == ""
                && ds_results.getCellData(i + 1, "reqHh") == ""
                && ds_results.getCellData(i + 1, "doorNm") == ""
                && ds_results.getCellData(i + 1, "doorCd") == ""
                && ds_results.getCellData(i + 1, "reqQty") == "0") {
                ds_results.setCellData(i + 1, "reqDt", ds_results.getCellData(i, "reqDt"));
                ds_results.setCellData(i + 1, "reqHh", ds_results.getCellData(i, "reqHh"));
                ds_results.setCellData(i + 1, "transCls", ds_results.getCellData(i, "transCls"));
                ds_results.setCellData(i + 1, "doorNm", ds_results.getCellData(i, "doorNm"));
                ds_results.setCellData(i + 1, "reqQty", ds_results.getCellData(i, "reqQty"));
                ds_results.setCellData(i + 1, "doorCd", ds_results.getCellData(i, "doorCd"));
                ds_results.setCellData(i + 1, "doorCdNm", ds_results.getCellData(i, "doorCdNm"));
                ds_results.setCellData(i + 1, "rmk", ds_results.getCellData(i, "rmk"));

                ds_results.modifyRowStatus(i, "U");
            }
        }

    }




    if (await $c.win.confirm(MSG_CM_CRM_001)) {
        $c.sbm.execute(sbm_save);
    }

    if (preChecked == "1") {
        cbx_retrvStpYn.setValue("1");
        scwin.f_filter();
    }
};


//-------------------------------------------------------------------------
// 필터
//-------------------------------------------------------------------------
scwin.f_filter = function () {
    ds_results.clearFilter();

    //회수숨기기
    let fn_tmpDeptFilter = function (cellData, tmpParam, rowIdx) {
        if (cbx_retrvStpYn.getValue() == "1") {
            if (ds_results.getCellData(rowIdx, "wrkStpCd") === DsConstants.WRK_STP_CD_RETRV) {
                return false;
            }
        }
        if (cbx_reqYn.getValue() == "1") {
            if (ds_results.getCellData(rowIdx, "remains") <= 0) {
                return false;
            }
        }

        return true;

    }

    ds_results.setColumnFilter(
        { type: "func", colIndex: "wrkStpCd", key: fn_tmpDeptFilter, condition: "and" }
    );

    let options = {
        sortIndex: "odrNo cntrSeq qty wrkStpCd dptWrkPlCd arvWrkPlCd",
        sortOrder: "1 1 1 1 1 1"
    }

    ds_results.multisort(options)


    spa_totalRows1.setValue(ds_results.getRowCount());



}


//-------------------------------------------------------------------------
// function name : f_deleteRow
// function desc : 배차취소 버튼 누를때 실행
//-------------------------------------------------------------------------
scwin.btn_cancelAllocated_onclick = async function (e) {

    let i = ds_results.getRowPosition();
    let arryCnt3 = 0;


    if (cbx_retrvStpYn.getValue() == "1") {
        $c.win.alert("취소는 회수숨기기를 해제하시고 하시기 바랍니다.");
        return;
    }


    if (ds_results.getCellData(i, "pastReqCnt") == "0") {
        $c.win.alert("취소할 물량이 없습니다..");
        return;
    }

    if (ds_results.getCellData(i, "reqClsCd") == "A" || ds_results.getCellData(i, "reqClsCd") == "B") {
        if (await $c.win.confirm(MSG_CM_CRM_001)) {

            ds_results.setCellData(i, "chk", "1");
            $c.sbm.execute(sbm_cancel);
        }
    } else if (ds_results.getCellData(i, "reqClsCd") == "C") {

        for (j = 0; j < ds_results2.getRowCount(); j++) {
            if (ds_results2.getCellData(j, "chk") == "1") {
                arryCnt3++;
            }
        }

        if (arryCnt3 < 1) {
            $c.win.alert("취소할 컨테이너가 없습니다.");
        } else {
            ds_results.setCellData(i, "chk", "1");
            $c.sbm.execute(sbm_cancel);
        }
    }

};

//-------------------------------------------------------------------------
// 작업경로 클릭 f_workPathMod2
//-------------------------------------------------------------------------
scwin.btn_resetWrkStp_onclick = async function (e) {
    let pURL = "";


    if (ds_results.getRowCount() == 0) {
        $c.win.alert($c.data.getMessage(MSG_CM_ERR_056, "대상물량")); //"선택된 @이(가) 없습니다.";
        return;
    }

    let sub = "";

    if (ds_results.getCellData(ds_results.getRowPosition(), "qty") == "1" && ds_results.getCellData(ds_results.getRowPosition(), "reqClsCd") == "A" && ds_results.getCellData(ds_results.getRowPosition(), "pastReqCnt") == "0") {

        // let arrParam = {
        //     odrNo: ds_results.getCellData(ds_results.getRowPosition(), "odrNo"),
        //     cntrSeq: ds_results.getCellData(ds_results.getRowPosition(), "cntrSeq"),
        //     qryClsCd: "fromOdrAlloc"
        // };

        let arrParam = [];
        arrParam[0] = ds_results.getCellData(ds_results.getRowPosition(), "odrNo");//오더번호
        arrParam[1] = ds_results.getCellData(ds_results.getRowPosition(), "cntrSeq");//컨테이너순번
        arrParam[2] = "fromOdrAlloc";

        if (scwin.loUpperLobranCd == "4BB") {
            pURL = "/ui/ds/op/wrkplan/transwrkplan/op_202_02_27p.xml";
        }
        else {
            let length = DsConstants.URL_CONTAINER_WORK_PATH_DETAIL_CHANGE_POPUP.length;
            let sub = DsConstants.URL_CONTAINER_WORK_PATH_DETAIL_CHANGE_POPUP.substring(0, (length - 3));
            pURL = ("/ui" + sub + "xml");
        }



        // 팝업 옵션 설정
        options = {
            id: "taxPop",
            type: "browserPopup",
            popupName: "작업경로상세정보변경(컨테이너)",
            width: 1100,
            height: 650
        };

        let rtnVal = await $c.win.openPopup(pURL, options, arrParam);

    } else {
        await $c.win.alert("지정인 경우에만 경로 수정이 가능합니다.");
        scwin.btn_retrieve_onclick();
        return;
    }

};


//-------------------------------------------------------------------------
// 저장 성공시
//-------------------------------------------------------------------------
scwin.sbm_save_submitdone = function (e) {
    try{
        if (e.responseJSON.resultDataSet[0].Code < 0)return; //onFail
        $c.win.alert(MSG_CM_INF_001) // 성공적으로 저장하였습니다.

        if (scwin.afterSaveRetrieveYN == "YES") {
            scwin.btn_retrieve_onclick();
        }
    } catch (e) {
       console.log("sbm_saveAcctRecvBdebt_submitdone : " + e);
    }

};

//-------------------------------------------------------------------------
// 취소 성공시
//-------------------------------------------------------------------------
scwin.sbm_cancel_submitdone = function (e) {
    try{
        if (e.responseJSON.resultDataSet[0].Code < 0)return; //onFail
            $c.win.alert(MSG_CM_INF_001) // 성공적으로 저장하였습니다.

            if (scwin.afterCancelRetrieveYN == "YES") {
                scwin.btn_retrieve_onclick();
            }
    } catch (e) {
       console.log("sbm_saveAcctRecvBdebt_submitdone : " + e);
    }
};


//-------------------------------------------------------------------------
// 조회 데이터 로드 완료시
//-------------------------------------------------------------------------
scwin.ds_results_ondataload = function () {
    let rowCnt = ds_results.getRowCount();

    if (rowCnt == 0) {
        $c.win.alert("조회된 데이터가 없습니다.");
        return;
    }
    ds_results2.removeAll();

    spa_totalRows1.setValue(rowCnt);

    gr_results.setFocusedCell(0, 1);

    scwin.f_filter();

    // let options = {
    //     sortIndex : "odrNo cntrSeq qty wrkStpCd dptWrkPlCd arvWrkPlCd",
    //     sortOrder : "0 0 0 0 0 0"
    // }

    // ds_results.multisort(options)




};

//-------------------------------------------------------------------------
// 컨테이너 목록 그리드 데이터 로드 완료시
//-------------------------------------------------------------------------
scwin.ds_results2_ondataload = function () {
    let rowCnt = ds_results2.getRowCount();

    if (rowCnt == 0) {
        $c.win.alert("조회된 데이터가 없습니다.");
        return false;
    }

    spa_totalRows2.setValue(0);

    let options = {
        sortIndex: "odrNo cntrSeq odrWrkPathSeq",
        sortOrder: "0 0 0"
    }

    ds_results2.multisort(options)


};


//-------------------------------------------------------------------------
// 배차요청 그리드 셀 편집 후 
//-------------------------------------------------------------------------
scwin.gr_results_onafteredit = function (rowIndex, columnIndex, value) {
    let colid = gr_results.getColumnID(columnIndex);
    let nextDt = scwin.nextDt;
    let pName = ds_results.getCellData(rowIndex, colid);
    let pOrgName = scwin.olddata;


    switch (colid) {
        case "reqDt":
            if (ds_results.getCellData(rowIndex, "remains") == 0) {

                alert("해당하는 모든 컨테이너가 요청 되었습니다.");
                ds_results.undoRow(rowIndex);

            }


            break;

        case "reqQty":
            if (ds_results.getCellData(rowIndex, "remains") == 0) {

                alert("해당하는 모든 컨테이너가 요청 되었습니다.");
                ds_results.undoRow(rowIndex);

            }
            ds_results.setCellData(rowIndex, "reqDt", scwin.nextDt);
            break;

        case "reqHh":
            if (ds_results.getCellData(rowIndex, "remains") == 0) {

                alert("해당하는 모든 컨테이너가 요청 되었습니다.");
                ds_results.undoRow(rowIndex);

            }

            break;
        case "transCls":
            if (ds_results.getCellData(rowIndex, "remains") == 0) {

                alert("해당하는 모든 컨테이너가 요청 되었습니다.");
                ds_results.undoRow(rowIndex);

            }

            break;
        case "doorNm":
            if (ds_results.getCellData(rowIndex, "remains") == 0) {

                alert("해당하는 모든 컨테이너가 요청 되었습니다.");
                ds_results.undoRow(rowIndex);

            }

            break;
        case "doorCdNm":
            if (pName != "" && pName != pOrgName) {
                scwin.f_openCommPopUpGrid(1, row, '', pName, 'T', 'T');

            } else if (pName == "") {
                ds_results.setCellData(rowIndex, "doorCd", "");
            }


            break;
        default:
            break;

    }

};



//-------------------------------------------------------------------------
// 화주 조회 UDC
//-------------------------------------------------------------------------
scwin.udc_bilgClnt_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_bilgClntNo, ed_bilgClntNm, 3, true);
};

scwin.udc_bilgClnt_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(3, ed_bilgClntNo.getValue(), ed_bilgClntNm.getValue(), 'F', 'F');
};

scwin.udc_bilgClnt_onviewchangeNameEvent = function (info) {
    scwin.f_chkOpenCommonPopUp(ed_bilgClntNm, ed_bilgClntNo, 3, false);
};

//-------------------------------------------------------------------------
// 라인 조회 UDC
//-------------------------------------------------------------------------
scwin.udc_line_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_lineCd, ed_lineNm, 4, true);
};

scwin.udc_line_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(4, ed_lineCd.getValue(), ed_lineNm.getValue(), 'F', 'F');
};

scwin.udc_line_onviewchangeNameEvent = function (info) {
    scwin.f_chkOpenCommonPopUp(ed_lineNm, ed_lineCd, 4, false)
};




//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {

    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
        return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    let pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
        scwin.f_openCommonPopUp(disGubun, pVal, "", "T", "T");
    // inObj가 코드명 필드일 경우 팝업
    else
        scwin.f_openCommonPopUp(disGubun, "", pVal, "T", "T");
}

//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {

    // 선언부
    let rtnList;  // 공통POP-UP -> 요청화면 
    switch (disGubun) {

        case 3:
            // 청구처
            udc_bilgClnt.cfCommonPopUp(scwin.udc_bilgClnt_CallBack
                , pCode					// 화면에서의 ??? Code Element의	Value
                , pName					// 화면에서의 ??? Name Element의	Value
                , pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                , null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                , null					// Title순서
                , null					// 보여주는 각 컬럼들의 폭
                , null					// 컬럼중에서 숨기는	컬럼 지정
                , null					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                , null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                , null					// POP-UP뛰을때 우도우의	사용자 정의	높이
                , null					// 윈도우 위치 Y좌표
                , null					// 윈도우 위치 X좌표
                , null					// 중복체크여부	("F")
                , pAllSearch					// 전체검색허용여부	("F")
                , "청구 거래처,청구 거래처코드/명"				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );

            break;

        case 4:
            // 청구처
            udc_line.cfCommonPopUp(scwin.udc_line_CallBack
                , pCode					// 화면에서의 ??? Code Element의	Value
                , pName					// 화면에서의 ??? Name Element의	Value
                , pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                , null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                , null					// Title순서
                , null					// 보여주는 각 컬럼들의 폭
                , null					// 컬럼중에서 숨기는	컬럼 지정
                , null					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                , null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                , null					// POP-UP뛰을때 우도우의	사용자 정의	높이
                , null					// 윈도우 위치 Y좌표
                , null					// 윈도우 위치 X좌표
                , null					// 중복체크여부	("F")
                , pAllSearch					// 전체검색허용여부	("F")
                , "라인,라인 코드/명"				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
            cfSetReturnValue(rtnList, ed_lineCd, txt_lineNm);

            break;
    }
}


