//-------------------------------------------------------------------------
scwin.gr_results2_onafteredit = function (rowIndex, columnIndex, value) {
    let colid = gr_results.getColumnID(columnIndex);

    let pName = ds_results2.getCellData(rowIndex, colid);
    let pOrgName = scwin.olddata;


    switch (colid) {

        case "doorCdNm":
            if (pName != "" && pName != pOrgName) {
                scwin.f_openCommPopUpGrid2(1, row, '', pName, 'T', 'T');
            } else if (pName == "") {
                ds_results2.setCellData(row, "doorCd", "");

            }

            break;

        default:

            break;
    }
};

