//-------------------------------------------------------------------------
// 배차요청 그리드 Cell Click
//-------------------------------------------------------------------------
scwin.gr_results_oncellclick = function (rowIndex, columnIndex, columnId) {

    switch (columnId) {

        case "reqQty":

            if (ds_results.getCellData(rowIndex, "remains") == 0) {
                $c.win.alert("요청할 수량이 없습니다");
                ds_results2.removeAll();
            }

            break;

        case "doorCdNm":


            if (ds_results.getCellData(rowIndex, "reqClsCd") == "A") {
                $c.win.alert("지정의 경우에는 입력할 수 없습니다.");
                gr_results.setCellReadOnly(rowIndex, "doorCdNm", true);
            } else {
                gr_results.setCellReadOnly(rowIndex, "doorCdNm", false);
            }


            if ((ds_results.getCellData(rowIndex, "reqClsCd") == "B" || ds_results.getCellData(rowIndex, "reqClsCd") == "C") && ds_results.getCellData(rowIndex, "arvWrkPlCd") != "43D" && ds_results.getCellData(rowIndex, "dptWrkPlCd") != "43D") {
                $c.win.alert("대표착지가 아닌 경우에는 입력할 수 없습니다.");
                gr_results.setCellReadOnly(rowIndex, "doorCdNm", true);
            } else {
                gr_results.setCellReadOnly(rowIndex, "doorCdNm", false);
            }

            break;

        case "doorNm":
            if (ds_results.getCellData(rowIndex, "reqClsCd") == "A") {
                $c.win.alert("지정의 경우에는 입력할 수 없습니다.");
                gr_results.setCellReadOnly(rowIndex, "doorCdNm", true);

            } else {
            }

            if ((ds_results.getCellData(rowIndex, "reqClsCd") == "B" || ds_results.getCellData(rowIndex, "reqClsCd") == "C") && ds_results.getCellData(rowIndex, "arvWrkPlCd") != "43D" && ds_results.getCellData(rowIndex, "dptWrkPlCd") != "43D") {
                $c.win.alert("대표착지가 아닌 경우에는 입력할 수 없습니다.");
                gr_results.setCellReadOnly(rowIndex, "doorCdNm", true);
            } else {
                gr_results.setCellReadOnly(rowIndex, "doorCdNm", false);
            }


            break;

        default:
            break;
    }
};


//-------------------------------------------------------------------------
// 구분 콤보박스 값 변경시
//-------------------------------------------------------------------------
scwin.acb_qryClsCd_onchange = function (info) {
    let qryClsCd = acb_qryClsCd.getValue();


    if (qryClsCd == "C") {
        cbx_retrvStpYn.setValue("");
        scwin.f_filter();
    }


    if (qryClsCd == "B" || qryClsCd == "C") {

        ed_cntrNo.setValue("");
        $c.gus.cfDisableObjects([ed_cntrNo]);


    } else {
        $c.gus.cfEnableObjects([ed_cntrNo]);
    }

};


scwin.ds_results_onrowpositionchange = function (info) {

    if (ds_results.getCellData(ds_results.getRowPosition(), "reqClsCd") == "C") {

        dma_search2.set("odrNo", ds_results.setCellData(ds_results.getRowPosition(), "odrNo"));
        dma_search2.set("wrkStpCd", ds_results.setCellData(ds_results.getRowPosition(), "wrkStpCd"));
        dma_search2.set("dptWrkPlCd", ds_results.setCellData(ds_results.getRowPosition(), "dptWrkPlCd"));
        dma_search2.set("arvWrkPlCd", ds_results.setCellData(ds_results.getRowPosition(), "arvWrkPlCd"));
        dma_search2.set("cntrSizCd", ds_results.setCellData(ds_results.getRowPosition(), "cntrSizCd"));
        dma_search2.set("cntrTypCd", ds_results.setCellData(ds_results.getRowPosition(), "cntrTypCd"));
        dma_search2.set("lobranCd", dma_search.get("lobranCd"));

        $c.sbm.execute(sbm_retrieve2);
    }


};


scwin.wrkSt_decode = function (data, formattedData, rowIndex, colIndex) {
    if (ds_results.getCellData(rowIndex, "wrkStpCd") == "0001") {
        return "셔틀";
    } else if (ds_results.getCellData(rowIndex, "wrkStpCd") == "0002") {
        return "운송";
    } else if (ds_results.getCellData(rowIndex, "wrkStpCd") == "0003") {
        return "회수";
    } else if (ds_results.getCellData(rowIndex, "wrkStpCd") == "0047") {
        return "육송";
    } else if (ds_results.getCellData(rowIndex, "wrkStpCd") == "0004") {
        return "철송";
    } else if (ds_results.getCellData(rowIndex, "wrkStpCd") == "0005") {
        return "해송";
    } else {
        return "기타";
    }
}


scwin.cntrNo_Format = function (data, formattedData, rowIndex, colIndex) {
    if (ds_results.getCellData(rowIndex, "qty") == "1") {
        gr_results.setHeaderColor("column71", "red");
    } else {
        gr_results.setHeaderColor("column71", "blue");
    }
    return data;

}

